import axios from "axios";
import { useFormik } from "formik";
import { useCookies } from "react-cookie";
import { useNavigate } from "react-router-dom";

export function UserLogin() {
    let navigate = useNavigate();
    const [cookies, setCookie, removeCookie] = useCookies(['user-id']);

    const formik = useFormik({
        initialValues: {
            UserId: '',
            Password: ''
        },
        onSubmit: (user) => {
            axios.get('http://127.0.0.1:3030/get-users')
                .then(response => {
                    const foundUser = response.data.find(item => item.UserId === user.UserId);
                    if (foundUser) {
                        if (foundUser.Password === user.Password) {
                            setCookie('user-id', user.UserId, { path: '/' });
                            navigate('/user-dashboard');
                        } else {
                            navigate('/user-error');
                        }
                    } else {
                        navigate('/user-error');
                    }
                });
        }
    });

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ height: '60vh' }}>
            <form className="w-25 border p-4 shadow rounded" onSubmit={formik.handleSubmit}>
                <div className="text-center mb-3 fs-4 fw-bold text-primary">
                    <i className="bi bi-person-circle me-2"></i>User Login
                </div>
                <div className="mb-3">
                    <label className="form-label">User ID</label>
                    <input type="text" name="UserId" onChange={formik.handleChange} className="form-control" required />
                </div>
                <div className="mb-3">
                    <label className="form-label">Password</label>
                    <input type="password" name="Password" onChange={formik.handleChange} className="form-control" required />
                </div>
                <button type="submit" className="btn btn-warning w-100">Login</button>
            </form>
        </div>
    );
}
